class Person {
  String name = '';
  int age = 0;

  void sayHello() {
    print('Hello, my name is $name');
  }
}

void main() {
  var person = Person();
  person.name = 'Alice';
  person.age = 30;
  person.sayHello();
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);

  void introduce() {
    print('I am $name and I am $age years old');
  }
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);

  Person.guest() {
    name = 'Guest';
    age = 18;
  }

  Person.fromJson(Map<String, dynamic> json)
      : name = json['name'],
        age = json['age'];
}

class Point {
  int x, y;

  Point(int x, int y) {
    this.x = x;
    this.y = y;
  }
}

class Rectangle {
  double _width;
  double height;

  Rectangle(this._width, this.height);

  double get area => _width * height;

  set width(double value) {
    if (value > 0) {
      _width = value;
    } else {
      throw ArgumentError('Width must be positive');
    }
  }
}

class MathUtils {
  static const double pi = 3.14159;

  static int add(int a, int b) => a + b;
}

class BankAccount {
  String _accountNumber;
  double _balance = 0;

  BankAccount(this._accountNumber);

  void deposit(double amount) {
    if (amount > 0) _balance += amount;
  }

  double get balance => _balance;
}

class Student {
  String name;
  int age;
  final int id;
  static int _nextId = 1000;

  Student(this.name, this.age) : id = _nextId++;

  Student.anonymous()
      : name = 'Anonymous',
        age = 0,
        id = _nextId++;

  void introduce() {
    print('Student #$id: $name, $age years old');
  }

  String get description => 'ID $id: $name ($age)';
}

